#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 scale = vec2(1280,1024)*uTexSize.zw; // 1280x1024 : the resolution i modelled this shader with
    float1 d = 0.005;
    float1 dx = ( GetBlur2(vUv + vec2(d,0)) - GetBlur2(vUv-vec2(d,0)) ).x*scale.x;
    float1 dy = ( GetBlur2(vUv + vec2(0,d)) - GetBlur2(vUv-vec2(0,d)) ).x*scale.y;
    float1 dxb = ( GetBlur2(vUv + vec2(d,0)) - GetBlur2(vUv-vec2(d,0)) ).x*scale.x;
    float1 dyb = ( GetBlur2(vUv + vec2(0,d)) - GetBlur2(vUv-vec2(0,d)) ).x*scale.y;
    vec2 my_uv = vUv - vec2(dx,dy)*0.01 + vec2(dxb,dyb)*0.003;



    vec2 v = 0.01;
    ret.x = texture( sampler_fw_main, my_uv -floor(my_uv)*0).x;




//--------------------------------

    my_uv = vUv + vec2(dy,-dx)*0.05*(1.2-GetBlur3(vUv).y);



    v = 0.01;
    ret.z = texture( sampler_fw_main, my_uv).z;




//--------------------------------

    d = 0.01;
    my_uv = vec2(-dy,dx)*0.045;

    dx = ( GetBlur2(vUv + vec2(d,0)) - GetBlur2(vUv-vec2(d,0)) ).y*scale.x;
    dy = ( GetBlur2(vUv + vec2(0,d)) - GetBlur2(vUv-vec2(0,d)) ).y*scale.y;
    my_uv += vUv - vec2(dx,dy)*0.03;
    v = 0.01;
    ret.y =texture( sampler_fw_main, my_uv).y;

vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((my_uv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y += (noise9).x*.5;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z += (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x += (noise9).z*.5;
    ret.x += (ret.x - GetBlur3(vUv).x)*.1;
    ret.x -= 0.01;
    ret.y += (ret.y - GetBlur3(my_uv).y)*0.1 - 0.01;
    ret.z += (ret.z - GetBlur1(vUv).z)*length(my_uv-vUv)*180/length(scale);
    ret.z *= 0.8;
    ret.z -= 0.01;





//ret = 0;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw;
    vec3 dx = ( GetPixel(vUv+vec2(1,0)*d)-GetPixel(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetPixel(vUv+vec2(0,1)*d)-GetPixel(vUv-vec2(0,1)*d) );
vec2 dz = vec2(dx.y,dy.y)*3;

d = uTexSize.zw*2;
dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

dz +=vec2(dx.y,dy.y);

vec3 bg = pow(length(dz)*0.8+0,0.7)*2 + GetBlur1(vUv).y*2;

ret = bg*vec3(0.2,0.3,0.6);
vec2 uv_swimmer =fract(0.5 + (vUv-0.5)+vec2(q19,q20)*vec2(-1,1));
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((dz.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;
ret = mix(ret,vec3(3,2,1),GetBlur3(uv_swimmer -vec2(dx.y,dy.y)).x);
ret = mix(ret,0,GetBlur2(uv_swimmer-dz).x);
ret = mix(ret,vec3(0,0,0),1.5*GetPixel(uv_swimmer).x);
ret-=slow_roam_sin.wzy*roam_cos.zxy*.4;

//ret = GetPixel(vUv);

  fragColor = ret;
}
